import { Pool, PoolClient } from 'pg';
import { pool } from '../../shared/db/connection';
import { LeaveRequest, CreateLeaveRequestDto, LeaveRequestQueryParams } from '../../shared/types/index';
import { ILeaveRepository } from './leave.repository';
import { IEmployeeService } from '../employee/employee.service';
import { IPolicyService } from '../policy/policy.service';
import { IBalanceService } from '../balance/balance.service';
import { IAuditService } from '../audit/audit.service';
import { INotificationService } from '../notification/notification.service';

export interface ILeaveService {
  submitLeaveRequest(dto: CreateLeaveRequestDto, employeeId: string): Promise<LeaveRequest>;
  approveLeaveRequest(id: string, approverId: string): Promise<LeaveRequest>;
  rejectLeaveRequest(id: string, approverId: string, reason?: string): Promise<LeaveRequest>;
  cancelLeaveRequest(id: string, employeeId: string): Promise<LeaveRequest>;
  getLeaveRequest(id: string): Promise<LeaveRequest | null>;
  listLeaveRequests(params: LeaveRequestQueryParams): Promise<{ data: LeaveRequest[]; total: number }>;
}

export class LeaveService implements ILeaveService {
  constructor(
    private readonly leaveRepository: ILeaveRepository,
    private readonly employeeService: IEmployeeService,
    private readonly policyService: IPolicyService,
    private readonly balanceService: IBalanceService,
    private readonly auditService: IAuditService,
    private readonly notificationService: INotificationService
  ) {}

  async submitLeaveRequest(dto: CreateLeaveRequestDto, employeeId: string): Promise<LeaveRequest> {
    const client: PoolClient = await pool.connect();
    try {
      await client.query('BEGIN');
      // validate employee active
      const employee = await this.employeeService.getEmployeeById(employeeId);
      if (!employee || employee.employment_status !== 'ACTIVE') {
        throw new Error('Employee is not active');
      }
      // validate entitlement
      await this.policyService.validateEntitlement(employeeId, dto.leave_type_id, dto.start_date, dto.end_date);
      // create leave request with status SUBMITTED
      const leaveRequest = await this.leaveRepository.create({ ...dto, employee_id: employeeId, status: 'SUBMITTED' }, client);
      // audit
      await this.auditService.recordAction({
        entity_type: 'leave_request',
        entity_id: leaveRequest.id,
        action: 'SUBMIT',
        new_values: leaveRequest,
        performed_by: employeeId
      }, client);
      // notification
      await this.notificationService.sendNotification({
        recipient_id: employeeId,
        type: 'LEAVE_SUBMITTED',
        title: 'Leave Request Submitted',
        message: `Your leave request from ${dto.start_date} to ${dto.end_date} has been submitted.`,
        related_entity_type: 'leave_request',
        related_entity_id: leaveRequest.id
      }, client);
      await client.query('COMMIT');
      return leaveRequest;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async approveLeaveRequest(id: string, approverId: string): Promise<LeaveRequest> {
    const client: PoolClient = await pool.connect();
    try {
      await client.query('BEGIN');
      const request = await this.leaveRepository.findById(id);
      if (!request) throw new Error('Leave request not found');
      if (request.status !== 'SUBMITTED') throw new Error('Only submitted requests can be approved');
      const updated = await this.leaveRepository.update(id, { status: 'APPROVED', approved_by: approverId, approved_at: new Date() }, client);
      await this.balanceService.deductBalance(request.employee_id, request.leave_type_id, request.start_date, request.end_date, client);
      await this.auditService.recordAction({
        entity_type: 'leave_request',
        entity_id: id,
        action: 'APPROVE',
        old_values: request,
        new_values: updated,
        performed_by: approverId
      }, client);
      await this.notificationService.sendNotification({
        recipient_id: request.employee_id,
        type: 'LEAVE_APPROVED',
        title: 'Leave Request Approved',
        message: `Your leave request from ${request.start_date} to ${request.end_date} has been approved.`,
        related_entity_type: 'leave_request',
        related_entity_id: id
      }, client);
      await client.query('COMMIT');
      return updated;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async rejectLeaveRequest(id: string, approverId: string, reason?: string): Promise<LeaveRequest> {
    const client: PoolClient = await pool.connect();
    try {
      await client.query('BEGIN');
      const request = await this.leaveRepository.findById(id);
      if (!request) throw new Error('Leave request not found');
      if (request.status !== 'SUBMITTED') throw new Error('Only submitted requests can be rejected');
      const updated = await this.leaveRepository.update(id, { status: 'REJECTED', reason }, client);
      await this.auditService.recordAction({
        entity_type: 'leave_request',
        entity_id: id,
        action: 'REJECT',
        old_values: request,
        new_values: updated,
        performed_by: approverId
      }, client);
      await this.notificationService.sendNotification({
        recipient_id: request.employee_id,
        type: 'LEAVE_REJECTED',
        title: 'Leave Request Rejected',
        message: `Your leave request from ${request.start_date} to ${request.end_date} has been rejected.${reason ? ' Reason: ' + reason : ''}`,
        related_entity_type: 'leave_request',
        related_entity_id: id
      }, client);
      await client.query('COMMIT');
      return updated;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async cancelLeaveRequest(id: string, employeeId: string): Promise<LeaveRequest> {
    const client: PoolClient = await pool.connect();
    try {
      await client.query('BEGIN');
      const request = await this.leaveRepository.findById(id);
      if (!request) throw new Error('Leave request not found');
      if (request.employee_id !== employeeId) throw new Error('Only the owner can cancel');
      if (request.status === 'CANCELLED') throw new Error('Request already cancelled');
      const wasApproved = request.status === 'APPROVED';
      const updated = await this.leaveRepository.update(id, { status: 'CANCELLED' }, client);
      if (wasApproved) {
        await this.balanceService.restoreBalance(request.employee_id, request.leave_type_id, request.start_date, request.end_date, client);
      }
      await this.auditService.recordAction({
        entity_type: 'leave_request',
        entity_id: id,
        action: 'CANCEL',
        old_values: request,
        new_values: updated,
        performed_by: employeeId
      }, client);
      await this.notificationService.sendNotification({
        recipient_id: request.employee_id,
        type: 'LEAVE_CANCELLED',
        title: 'Leave Request Cancelled',
        message: `Your leave request from ${request.start_date} to ${request.end_date} has been cancelled.`,
        related_entity_type: 'leave_request',
        related_entity_id: id
      }, client);
      await client.query('COMMIT');
      return updated;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async getLeaveRequest(id: string): Promise<LeaveRequest | null> {
    return this.leaveRepository.findById(id);
  }

  async listLeaveRequests(params: LeaveRequestQueryParams): Promise<{ data: LeaveRequest[]; total: number }> {
    return this.leaveRepository.findAll(params);
  }
