import { FastifyRequest, FastifyReply } from 'fastify';
import { z } from 'zod';
import { ILeaveService } from './leave.service';
import { CreateLeaveRequestDto, LeaveRequestQueryParams } from '../../shared/types/index';

export interface AuthenticatedRequest extends FastifyRequest {
  user: {
    employeeId: string;
    role: string;
  };
}

const createLeaveRequestSchema = z.object({
  leave_type_id: z.string().uuid(),
  start_date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/),
  end_date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/),
  reason: z.string().optional()
});

const leaveRequestQuerySchema = z.object({
  employee_id: z.string().uuid().optional(),
  status: z.enum(['DRAFT','SUBMITTED','APPROVED','REJECTED','CANCELLED']).optional(),
  start_date: z.string().optional(),
  end_date: z.string().optional(),
  page: z.coerce.number().int().min(1).default(1),
  limit: z.coerce.number().int().min(1).max(100).default(20)
});

export const submitLeaveRequestHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const body = createLeaveRequestSchema.parse(req.body);
      const dto: CreateLeaveRequestDto = {
        leave_type_id: body.leave_type_id,
        start_date: body.start_date,
        end_date: body.end_date,
        reason: body.reason
      };
      const result = await leaveService.submitLeaveRequest(dto, req.user.employeeId);
      return reply.status(201).send(result);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return reply.status(400).send({ message: 'Validation error', errors: error.errors });
      }
      if (error instanceof Error) {
        const status = error.message.includes('not active') ? 403 : error.message.includes('not found') ? 404 : 400;
        return reply.status(status).send({ message: error.message });
      }
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };

export const approveLeaveRequestHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const { id } = req.params as { id: string };
      const result = await leaveService.approveLeaveRequest(id, req.user.employeeId);
      return reply.send(result);
    } catch (error) {
      if (error instanceof Error) {
        const status = error.message.includes('not found') ? 404 : 400;
        return reply.status(status).send({ message: error.message });
      }
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };

export const rejectLeaveRequestHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const { id } = req.params as { id: string };
      const { reason } = req.body as { reason?: string };
      const result = await leaveService.rejectLeaveRequest(id, req.user.employeeId, reason);
      return reply.send(result);
    } catch (error) {
      if (error instanceof Error) {
        const status = error.message.includes('not found') ? 404 : 400;
        return reply.status(status).send({ message: error.message });
      }
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };

export const cancelLeaveRequestHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const { id } = req.params as { id: string };
      const result = await leaveService.cancelLeaveRequest(id, req.user.employeeId);
      return reply.send(result);
    } catch (error) {
      if (error instanceof Error) {
        const status = error.message.includes('not found') ? 404 : 400;
        return reply.status(status).send({ message: error.message });
      }
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };

export const getLeaveRequestHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const { id } = req.params as { id: string };
      const result = await leaveService.getLeaveRequest(id);
      if (!result) return reply.status(404).send({ message: 'Leave request not found' });
      return reply.send(result);
    } catch (error) {
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };

export const listLeaveRequestsHandler = (leaveService: ILeaveService) =>
  async (req: AuthenticatedRequest, reply: FastifyReply) => {
    try {
      const query = leaveRequestQuerySchema.parse(req.query);
      const params: LeaveRequestQueryParams = {
        employee_id: query.employee_id,
        status: query.status,
        start_date: query.start_date,
        end_date: query.end_date,
        page: query.page,
        limit: query.limit
      };
      const result = await leaveService.listLeaveRequests(params);
      return reply.send(result);
    } catch (error) {
      if (error instanceof z.ZodError) {
        return reply.status(400).send({ message: 'Validation error', errors: error.errors });
      }
      return reply.status(500).send({ message: 'Internal server error' });
    }
  };","File: src/modules/leave/leave.routes.ts
import { FastifyInstance } from 'fastify';
import { ILeaveService } from './leave.service';
import {
  submitLeaveRequestHandler,
  approveLeaveRequestHandler,
  rejectLeaveRequestHandler,
  cancelLeaveRequestHandler,
  getLeaveRequestHandler,
  listLeaveRequestsHandler
} from './leave.controller';
import { authenticate, authorize } from '../../shared/middleware/auth';

export async function leaveRoutes(fastify: FastifyInstance, leaveService: ILeaveService) {
  fastify.post('/leave/requests', {
    preHandler: [authenticate, authorize('employee')]
  }, submitLeaveRequestHandler(leaveService));

  fastify.patch('/leave/requests/:id/approve', {
    preHandler: [authenticate, authorize('manager')]
  }, approveLeaveRequestHandler(leaveService));

  fastify.patch('/leave/requests/:id/reject', {
    preHandler: [authenticate, authorize('manager')]
  }, rejectLeaveRequestHandler(leaveService));

  fastify.patch('/leave/requests/:id/cancel', {
    preHandler: [authenticate, authorize('employee')]
  }, cancelLeaveRequestHandler(leaveService));

  fastify.get('/leave/requests/:id', {
    preHandler: [authenticate]
  }, getLeaveRequestHandler(leaveService));

  fastify.get('/leave/requests', {
    preHandler: [authenticate]
  }, listLeaveRequestsHandler(leaveService));
}","File: tests/unit/modules/leave/leave.service.test.ts
